import React, { useState } from "react";
import { BrowserRouter, Routes, Route, NavLink, useLocation } from "react-router-dom";
import { ToastProvider } from "./utils/toast";
import Dashboard   from "./pages/Dashboard";
import Students    from "./pages/Students";
import StudentDetail from "./pages/StudentDetail";
import Attendance  from "./pages/Attendance";
import Assignments from "./pages/Assignments";
import Calendar    from "./pages/Calendar";

const NAV_SECTIONS = [
  {
    label: "Overview",
    links: [
      { to: "/",         label: "Dashboard",   icon: "🏠", desc: "Class summary" },
      { to: "/calendar", label: "Calendar",     icon: "📆", desc: "Events & schedule" },
    ]
  },
  {
    label: "Class",
    links: [
      { to: "/students",    label: "Students",    icon: "👥", desc: "Manage members" },
      { to: "/attendance",  label: "Attendance",  icon: "✅", desc: "Weekly sessions" },
      { to: "/assignments", label: "Assignments", icon: "📋", desc: "Track submissions" },
    ]
  }
];

function Sidebar({ open, onClose }) {
  const location = useLocation();
  return (
    <>
      {open && <div className="sidebar-overlay" onClick={onClose} />}
      <nav className={`sidebar ${open ? "open" : ""}`}>

        {/* Logo */}
        <div className="sidebar-logo">
          <div className="sidebar-logo-mark">D</div>
          <div>
            <h1>Discipleship</h1>
            <small>Class Manager</small>
          </div>
        </div>

        {/* Nav sections */}
        <div className="sidebar-nav">
          {NAV_SECTIONS.map((section) => (
            <div key={section.label} className="sidebar-section">
              <div className="sidebar-section-label">{section.label}</div>
              {section.links.map((n) => {
                const isActive = n.to === "/"
                  ? location.pathname === "/"
                  : location.pathname.startsWith(n.to);
                return (
                  <NavLink
                    key={n.to}
                    to={n.to}
                    end={n.to === "/"}
                    className={`nav-link ${isActive ? "active" : ""}`}
                    onClick={onClose}
                  >
                    <span className="nav-icon-wrap">{n.icon}</span>
                    <div className="nav-text">
                      <span className="nav-label">{n.label}</span>
                      <span className="nav-desc">{n.desc}</span>
                    </div>
                    {isActive && <span className="nav-active-dot" />}
                  </NavLink>
                );
              })}
            </div>
          ))}
        </div>

        {/* Bottom user card */}
        <div className="sidebar-footer-card">
          <div className="sidebar-avatar">AS</div>
          <div className="sidebar-user-info">
            <div className="sidebar-user-name">Amanuel</div>
            <div className="sidebar-user-role">Class Leader</div>
          </div>
          <div className="sidebar-status-dot" title="Active" />
        </div>

      </nav>
    </>
  );
}

function Shell() {
  const [menuOpen, setMenuOpen] = useState(false);
  return (
    <div className="app-shell">
      <header className="mobile-header">
        <h1>Discipleship</h1>
        <button className="hamburger" onClick={() => setMenuOpen(v => !v)}>☰</button>
      </header>
      <Sidebar open={menuOpen} onClose={() => setMenuOpen(false)} />
      <main className="main-content">
        <Routes>
          <Route path="/"             element={<Dashboard />} />
          <Route path="/students"     element={<Students />} />
          <Route path="/students/:id" element={<StudentDetail />} />
          <Route path="/attendance"   element={<Attendance />} />
          <Route path="/assignments"  element={<Assignments />} />
          <Route path="/calendar"     element={<Calendar />} />
        </Routes>
      </main>
    </div>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <ToastProvider><Shell /></ToastProvider>
    </BrowserRouter>
  );
}
